import{_ as e,c as t,o as r,a2 as i}from"./chunks/framework.CP8b5y1j.js";const p=JSON.parse('{"title":"2026年学习日志","description":"","frontmatter":{},"headers":[],"relativePath":"src/other/2026年的碎碎念.md","filePath":"src/other/2026年的碎碎念.md","lastUpdated":1775093885000}'),o={name:"src/other/2026年的碎碎念.md"};function h(l,a,s,n,_,d){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="_2026年学习日志" tabindex="-1">2026年学习日志 <a class="header-anchor" href="#_2026年学习日志" aria-label="Permalink to &quot;2026年学习日志&quot;">​</a></h1><p>偶尔记录心情，记录生活，记录工作，记录学习，记录生活中的感触，记录生活中的喜怒哀乐。不知道记录啥随便写的.....</p><h2 id="_2026-4-1" tabindex="-1">2026.4.1 <a class="header-anchor" href="#_2026-4-1" aria-label="Permalink to &quot;2026.4.1&quot;">​</a></h2><p>今天是愚人节，现在是早上06:43.最近作息调整到晚上九点睡觉，早上五点半醒来，一时不知道是好是坏，感觉作息还是蛮健康的....</p><h2 id="_2026-3-25" tabindex="-1">2026.3.25 <a class="header-anchor" href="#_2026-3-25" aria-label="Permalink to &quot;2026.3.25&quot;">​</a></h2><p>考研成绩2.28号出的，没考上....最近学完了vue3，并且练习了半个项目，有些方面还是不熟练。现在准备练习Tailwindcss，并尝试用Tailwindcss来改写一个项目。最近还在学封装Axios，学习RBAC权限管理。</p><h2 id="_2026-2-25" tabindex="-1">2026.2.25 <a class="header-anchor" href="#_2026-2-25" aria-label="Permalink to &quot;2026.2.25&quot;">​</a></h2><p>本来是说24号出考研初试成绩的，结果兜兜转转没出，没有人知道为什么，也没有人知道今年的成绩什么时候出。。。</p><h2 id="_2026-2-2" tabindex="-1">2026.2.2 <a class="header-anchor" href="#_2026-2-2" aria-label="Permalink to &quot;2026.2.2&quot;">​</a></h2><p>ajax、JavaScript和vite学完，最近效率还不错....</p><h2 id="_2026-1-27" tabindex="-1">2026.1.27 <a class="header-anchor" href="#_2026-1-27" aria-label="Permalink to &quot;2026.1.27&quot;">​</a></h2><p>学完了前端三件套基础知识，感觉学习时间有点太长了，最近学习效率不怎么高！下面开始学习Ajax和tailwindcss,之后是vite。</p><h2 id="_2026-1-15" tabindex="-1">2026.1.15 <a class="header-anchor" href="#_2026-1-15" aria-label="Permalink to &quot;2026.1.15&quot;">​</a></h2><p>加入L站！解锁新天地！</p><h2 id="_2026-1-4" tabindex="-1">2026.1.4 <a class="header-anchor" href="#_2026-1-4" aria-label="Permalink to &quot;2026.1.4&quot;">​</a></h2><p>大晚上的连不上github，代码推不上去.....感觉一干正事，机场就不太好用了。之前不学习的时候，也没觉得这个机场有什么不好用的。现在一天推三四次代码，感觉就一次能推上去。要是之后再影响体验就换一个好点的。</p>',16)])])}const u=e(o,[["render",h]]);export{p as __pageData,u as default};
